export function formatDate(d: Date): string {
  return d.toISOString().slice(0, 10);
}

export function todayLabel(): string {
  return formatDate(new Date());
}

export function rangeLabel(start: Date, end: Date): string {
  return formatDate(start) + " to " + formatDate(end);
}

export function dueLabel(d: Date): string {
  return "due " + formatDate(d);
}

export function createdLabel(d: Date): string {
  return "created " + formatDate(d);
}

export function logLine(when: Date, msg: string): string {
  return "[" + formatDate(when) + "] " + msg;
}

export function auditRow(when: Date, who: string): string {
  return formatDate(when) + " " + who;
}

export function shortDate(d: Date): string {
  return formatDate(d).slice(5);
}

